package com.rabitah.frontend.api;
import com.fasterxml.jackson.databind.*; import com.fasterxml.jackson.datatype.jsr310.JavaTimeModule; import com.rabitah.frontend.session.SessionManager; import java.net.*; import java.net.http.*; import java.time.Duration; import java.util.concurrent.*;
public final class ApiClient {private final URI base;private final SessionManager session;private final Executor executor;private final HttpClient http;private final ObjectMapper json=new ObjectMapper().registerModule(new JavaTimeModule());public ApiClient(URI base,SessionManager session,Executor executor){this.base=base;this.session=session;this.executor=executor;this.http=HttpClient.newBuilder().connectTimeout(Duration.ofSeconds(10)).executor(executor).build();}public <T> CompletableFuture<T> post(String path,Object body,Class<T> type){try{var b=HttpRequest.newBuilder(base.resolve(path)).timeout(Duration.ofSeconds(30)).header("Content-Type","application/json").POST(HttpRequest.BodyPublishers.ofString(json.writeValueAsString(body)));if(session.accessToken()!=null)b.header("Authorization","Bearer "+session.accessToken());return http.sendAsync(b.build(),HttpResponse.BodyHandlers.ofString()).thenApplyAsync(r->{if(r.statusCode()<200||r.statusCode()>=300)throw new ApiClientException(r.statusCode(),message(r.body()));try{return json.readValue(r.body(),type);}catch(Exception e){throw new ApiClientException(r.statusCode(),"The server returned an unreadable response",e);}},executor);}catch(Exception e){return CompletableFuture.failedFuture(e);}}private String message(String body){try{return json.readTree(body).path("message").asText("Request failed");}catch(Exception e){return "Request failed";}}public static final class ApiClientException extends RuntimeException{private final int status;public ApiClientException(int status,String message){super(message);this.status=status;}public ApiClientException(int status,String message,Throwable cause){super(message,cause);this.status=status;}public int status(){return status;}}}
